let cols = rows.shift();

for (let r=0; r<rows.length; ++r)
{
	let obj = {};
	for (let c=0; c<cols.length; ++c)
	{
		obj[cols[c]] = rows[r][c];
	}
	rows[r] = obj;
}

// build the table subset to show the client
let table_data = [];

for (let i=0; i<rows.length; ++i)
{
	let r = rows[i];

	//ID,Herbarium,FloraBase,Status,Species,FastA,FastQ
	//["index","id","plate","well","sample","florabase","sheet_id","exclude_cpt","family","name","filename","url_fastq"],
	table_data.push([

		// local ID, clicks to open full metadata record
		`<a onclick='show_metadata(${i});'>${r.id}</a>`,

		// herbarium or ausplot ID
		r.sheet_id,

		// florabase link
		r.florabase ? `<a target='new' href='https://florabase.dpaw.wa.gov.au/browse/profile/${r.florabase}'>${r.florabase}</a>` : '',

		// status
		r.exclude_cpt === "true" ? 'query' : 'ok',

		// family
		r.family,

		// itallicised species
		`<em>${r.name.split("_").join(' ')}</em>`,

		// link to genome FastA file
		r.filename ? `<a target='new' href='data/sequences/${r.filename}'>FastA</a>` : '',

		// link to rDNA FastA file
		//r.rdna_file ? `<a target='new' href='data/rdna/rdna_${r.id}.fa'>FastA</a>` : '',

		// link to FastQ data store
		//`<a target='new' href='https://downloads-qcif.bioplatforms.com/bpa/barcode/pilbara_flora/sets/metagenomics/agrf/${r.url_fastq}'>FastQ</a>`
		`<a target='new' href='${r.url_fastq}'>FastQ</a>`
	]);
}
let dt = $('#table').DataTable({
	scrollY : "600px",
	scrollCollapse : true,
	paging : false,
	data : table_data,
	order : [[4,'asc'],[5,'asc']]
});
